<?php
$adminSection = 'reviews'; require __DIR__ . '/partials/header.php';
if ($_SERVER['REQUEST_METHOD'] === 'POST') { verify_csrf(); $author = trim((string) ($_POST['author_name'] ?? '')); $rating = max(1, min(5, (int) ($_POST['rating'] ?? 5))); $content = trim((string) ($_POST['content'] ?? '')); if ($author !== '' && $content !== '') { db_execute('INSERT INTO reviews (author_name, rating, content, is_visible, sort_order) VALUES (?, ?, ?, 1, ?)', [$author, $rating, $content, (int) time()]); flash('success','Avis ajouté.'); } else { flash('error','Merci de remplir le nom et le texte de l’avis.'); } redirect_to('admin/reviews.php'); }
if (isset($_GET['toggle'])) { $id = (int) $_GET['toggle']; $row = db_fetch('SELECT is_visible FROM reviews WHERE id = ?', [$id]); if ($row) db_execute('UPDATE reviews SET is_visible = ? WHERE id = ?', [(int) !$row['is_visible'], $id]); redirect_to('admin/reviews.php'); }
$reviews = db_fetch_all('SELECT * FROM reviews ORDER BY sort_order ASC, id DESC');
?><div class="admin-page-toolbar"><div><div class="admin-breadcrumb">Contenus</div><h1 class="admin-page-title">Avis</h1><p class="admin-page-subtitle">Les avis visibles remontent sur la page d’accueil.</p></div></div><div class="admin-stack"><section class="admin-panel"><div class="admin-panel__head"><h2>Ajouter un avis</h2></div><div class="admin-panel__body"><form method="post" class="admin-form-grid admin-form-grid--2"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()) ?>"><label class="admin-field"><span>Auteur</span><input type="text" name="author_name" required></label><label class="admin-field"><span>Note /5</span><input type="number" name="rating" min="1" max="5" value="5"></label><label class="admin-field" style="grid-column:1/-1"><span>Contenu</span><textarea name="content" rows="4" required></textarea></label><div class="admin-savebar" style="grid-column:1/-1;justify-content:flex-start"><button class="admin-btn admin-btn--primary" type="submit">Ajouter</button></div></form></div></section><section class="admin-panel"><div class="admin-panel__head"><h2>Liste des avis</h2></div><div class="admin-panel__body admin-table-wrap"><table class="admin-table"><thead><tr><th>Auteur</th><th>Note</th><th>Texte</th><th>Visible</th><th>Action</th></tr></thead><tbody><?php foreach ($reviews as $review): ?><tr><td><?= e($review['author_name']) ?></td><td><?= e((string) $review['rating']) ?>/5</td><td><?= e($review['content']) ?></td><td><?= (int) $review['is_visible'] === 1 ? 'Oui' : 'Non' ?></td><td><a class="admin-btn admin-btn--secondary" href="<?= e(url_for('admin/reviews.php?toggle=' . (int) $review['id'])) ?>"><?= (int) $review['is_visible'] === 1 ? 'Masquer' : 'Afficher' ?></a></td></tr><?php endforeach; ?></tbody></table></div></section></div><?php require __DIR__ . '/partials/footer.php'; ?>